@app.get("/health")
def health():
    client = get_memcache_client()
    ok = True
    try:
        client.set("healthcheck", b"1", expire=2)
        ok = client.get("healthcheck") == b"1"
    except Exception:
        ok = False
    return jsonify({"status": "ok" if ok else "degraded"}), (200 if ok else 503)


